func NewAuditFormatter(salter Salter, logger useEventLogger) (*AuditFormatter, error) {
	if salter == nil {
		return nil, errors.New("cannot create a new audit formatter with nil salter")
	}
	if logger == nil {
		return nil, errors.New("cannot create a new audit formatter with nil logger")
	}
	return &AuditFormatter{salter: salter, logger: logger}, nil
}

